SELECT type_id, type_name
FROM message_types
ORDER BY type_id;

SELECT type_name
FROM message_types
WHERE type_id = 1;

SELECT type_name
FROM message_types
WHERE description LIKE '%important%';

SELECT COUNT(*) AS message_type_count
   FROM message_types
   WHERE type_id > 1;

SELECT type_name
FROM message_types
ORDER BY type_name ASC;
